import random

MAX_LEVEL = 4

class SkipNode:
    def __init__(self, key, val, level):
        self.key  = key
        self.val  = val
        self.next = [None] * (level + 1)  # forward pointers per level

class SkipList:
    def __init__(self):
        self.head  = SkipNode(float('-inf'), None, MAX_LEVEL)
        self.level = 0

    def _random_level(self):
        lvl = 0
        while random.random() < 0.5 and lvl < MAX_LEVEL:
            lvl += 1
        return lvl

    def search(self, target):
        cur = self.head
        for i in range(self.level, -1, -1):    # top level down to 0
            while cur.next[i] and ___________: # advance while key < target
                cur = cur.next[i]
        cur = cur.next[0]                       # bottom level, one step right
        return cur.val if cur and cur.key == target else -1
